INSERT INTO wiki_relic (relic_id,name,pool,tier,description,description_raw,flavor,ancient,compendium_order,image,page) VALUES ('paels_tooth', '佩尔之牙', '通用', '先古之民', '拾起时，从你的{{颜色|gold|牌组}}中选择{{颜色|blue|5}}张牌移除。在每场战斗结束时，将其中随机{{颜色|blue|1}}张牌{{颜色|gold|升级}}然后返还。', '拾起时，从你的牌组中选择5张牌移除。在每场战斗结束时，将其中随机1张牌升级然后返还。', '{{颜色|red|这个遗物的细节将在未来揭晓……}}', '佩尔', '197', 'paels_tooth.png', '佩尔之牙');
INSERT INTO wiki_relic (relic_id,name,pool,tier,description,description_raw,flavor,ancient,compendium_order,image,page) VALUES ('paels_eye', '佩尔之眼', '通用', '先古之民', '你在每场战斗中第一次没有打出任何牌就结束回合时，{{颜色|gold|消耗}}所有{{颜色|gold|手牌}}然后进行一个额外回合。', '你在每场战斗中第一次没有打出任何牌就结束回合时，消耗所有手牌然后进行一个额外回合。', '{{颜色|red|这个遗物的细节将在未来揭晓……}}', '佩尔', '198', 'paels_eye.png', '佩尔之眼');
INSERT INTO wiki_relic (relic_id,name,pool,tier,description,description_raw,flavor,ancient,compendium_order,image,page) VALUES ('paels_wing', '佩尔之翼', '通用', '先古之民', '你可以将你的卡牌奖励献祭给佩尔。每献祭{{颜色|blue|2}}次，就能获得一件{{颜色|gold|遗物}}。', '你可以将你的卡牌奖励献祭给佩尔。每献祭2次，就能获得一件遗物。', '{{颜色|red|这个遗物的细节将在未来揭晓……}}', '佩尔', '199', 'paels_wing.png', '佩尔之翼');
INSERT INTO wiki_relic (relic_id,name,pool,tier,description,description_raw,flavor,ancient,compendium_order,image,page) VALUES ('paels_claw', '佩尔之爪', '通用', '先古之民', '拾起时，为所有的“{{颜色|gold|防御}}”{{颜色|gold|附魔}}：{{颜色|purple|黏糊}}。', '拾起时，为所有的“防御”附魔：黏糊。', '{{颜色|red|这个遗物的细节将在未来揭晓……}}', '佩尔', '200', 'paels_claw.png', '佩尔之爪');
INSERT INTO wiki_relic (relic_id,name,pool,tier,description,description_raw,flavor,ancient,compendium_order,image,page) VALUES ('biiig_hug', '大～抱抱', '通用', '先古之民', '拾起时，从你的{{颜色|gold|牌组}}中移除{{颜色|blue|4}}张牌。每当你的{{颜色|gold|抽牌堆}}打乱洗牌时，将一张{{颜色|gold|煤灰}}加入你的{{颜色|gold|抽牌堆}}。', '拾起时，从你的牌组中移除4张牌。每当你的抽牌堆打乱洗牌时，将一张煤灰加入你的抽牌堆。', '{{颜色|red|这个遗物的细节将在未来揭晓……}}', '特兹卡塔拉', '201', 'biiig_hug.png', '大～抱抱');
INSERT INTO wiki_relic (relic_id,name,pool,tier,description,description_raw,flavor,ancient,compendium_order,image,page) VALUES ('storybook', '故事书', '通用', '先古之民', '拾起时，将{{颜色|blue|1}}张{{颜色|gold|至亮之焰}}添加到你的{{颜色|gold|牌组}}中。', '拾起时，将1张至亮之焰添加到你的牌组中。', '{{颜色|red|这个遗物的细节将在未来揭晓……}}', '特兹卡塔拉', '202', 'storybook.png', '故事书');
INSERT INTO wiki_relic (relic_id,name,pool,tier,description,description_raw,flavor,ancient,compendium_order,image,page) VALUES ('toasty_mittens', '烘焙手套', '通用', '先古之民', '在你的回合开始时，{{颜色|gold|消耗}}你{{颜色|gold|抽牌堆}}顶部的牌并获得{{颜色|blue|1}}点{{颜色|gold|力量}}。', '在你的回合开始时，消耗你抽牌堆顶部的牌并获得1点力量。', '{{颜色|red|这个遗物的细节将在未来揭晓……}}', '特兹卡塔拉', '203', 'toasty_mittens.png', '烘焙手套');
INSERT INTO wiki_relic (relic_id,name,pool,tier,description,description_raw,flavor,ancient,compendium_order,image,page) VALUES ('golden_compass', '黄金罗盘', '通用', '先古之民', '拾起时，将第{{颜色|blue|2}}{{颜色|gold|阶段}}的地图替换为一条特殊的直道。', '拾起时，将第2阶段的地图替换为一条特殊的直道。', '{{颜色|red|这个遗物的细节将在未来揭晓……}}', '特兹卡塔拉', '204', 'golden_compass.png', '黄金罗盘');
INSERT INTO wiki_relic (relic_id,name,pool,tier,description,description_raw,flavor,ancient,compendium_order,image,page) VALUES ('seal_of_gold', '黄金印', '通用', '先古之民', '在你的回合开始时，花费{{颜色|blue|5}}{{颜色|gold|金币}}来获得[[File:colorless_energy_icon.png|16px|link=能量]]。', '在你的回合开始时，花费5金币来获得能量。', '{{颜色|red|这个遗物的细节将在未来揭晓……}}', '特兹卡塔拉', '205', 'seal_of_gold.png', '黄金印');
INSERT INTO wiki_relic (relic_id,name,pool,tier,description,description_raw,flavor,ancient,compendium_order,image,page) VALUES ('yummy_cookie', '美味饼干', '通用', '先古之民', '拾起时，{{颜色|gold|升级}}{{颜色|blue|4}}张牌。', '拾起时，升级4张牌。', '{{颜色|red|这个遗物的细节将在未来揭晓……}}', '特兹卡塔拉', '206', 'yummy_cookie.png', '美味饼干');
INSERT INTO wiki_relic (relic_id,name,pool,tier,description,description_raw,flavor,ancient,compendium_order,image,page) VALUES ('pumpkin_candle', '南瓜蜡烛', '通用', '先古之民', '在每个回合开始时获得[[File:colorless_energy_icon.png|16px|link=能量]]。这件遗物将在第{{颜色|blue|3}}{{颜色|gold|阶段}}开始时熄灭。', '在每个回合开始时获得能量。这件遗物将在第3阶段开始时熄灭。', '{{颜色|red|这个遗物的细节将在未来揭晓……}}', '特兹卡塔拉', '207', 'pumpkin_candle.png', '南瓜蜡烛');
