INSERT INTO wiki_relic (relic_id,name,pool,tier,description,description_raw,flavor,ancient,compendium_order,image,page) VALUES ('toy_box', '玩具盒', '通用', '先古之民', '拾起时，获得{{颜色|blue|4}}件{{颜色|gold|蜡制遗物}}。每经过{{颜色|blue|3}}场战斗，你最左侧的{{颜色|gold|蜡制遗物}}将会融化。', '拾起时，获得4件蜡制遗物。每经过3场战斗，你最左侧的蜡制遗物将会融化。', '{{颜色|red|这个遗物的细节将在未来揭晓……}}', '特兹卡塔拉', '209', 'toy_box.png', '玩具盒');
