INSERT INTO wiki_relic (relic_id,name,pool,tier,description,description_raw,flavor,ancient,compendium_order,image,page) VALUES ('blessed_antler', '赐福鹿角', '通用', '先古之民', '在每回合开始时获得[[File:colorless_energy_icon.png|16px|link=能量]]。在战斗开始时，将{{颜色|blue|3}}张{{颜色|gold|晕眩}}放入你的{{颜色|gold|抽牌堆}}。', '在每回合开始时获得能量。在战斗开始时，将3张晕眩放入你的抽牌堆。', '{{颜色|red|这个遗物的细节将在未来揭晓……}}', '诺奴佩普', '212', 'blessed_antler.png', '赐福鹿角');
