INSERT INTO wiki_relic (relic_id,name,pool,tier,description,description_raw,flavor,ancient,compendium_order,image,page) VALUES ('blood_soaked_rose', '血染玫瑰', '通用', '先古之民', '拾起时，将{{颜色|blue|1}}张{{颜色|red|执迷}}加入你的{{颜色|gold|牌组}}。在回合开始时获得[[File:colorless_energy_icon.png|16px|link=能量]]。', '拾起时，将1张执迷加入你的牌组。在回合开始时获得能量。', '{{颜色|red|这个遗物的细节将在未来揭晓……}}', '瓦库', '236', 'blood_soaked_rose.png', '血染玫瑰');
