SET NAMES utf8mb4;

-- 建表（如已存在则跳过）
CREATE TABLE IF NOT EXISTS wiki_card (
  id INT AUTO_INCREMENT PRIMARY KEY,
  card_id VARCHAR(64),
  name VARCHAR(128),
  color VARCHAR(64),
  rarity VARCHAR(64),
  card_type VARCHAR(64),
  cost VARCHAR(16),
  description TEXT,
  description_raw TEXT,
  upgrade_ref VARCHAR(64),
  compendium_order INT DEFAULT 0,
  image VARCHAR(256),
  page VARCHAR(256)
) CHARACTER SET utf8mb4;

CREATE TABLE IF NOT EXISTS wiki_relic (
  id INT AUTO_INCREMENT PRIMARY KEY,
  relic_id VARCHAR(64),
  name VARCHAR(128),
  pool VARCHAR(64),
  tier VARCHAR(64),
  description TEXT,
  description_raw TEXT,
  flavor TEXT,
  ancient VARCHAR(16),
  compendium_order INT DEFAULT 0,
  image VARCHAR(256),
  page VARCHAR(256)
) CHARACTER SET utf8mb4;

CREATE TABLE IF NOT EXISTS wiki_potion (
  id INT AUTO_INCREMENT PRIMARY KEY,
  potion_id VARCHAR(64),
  name VARCHAR(128),
  color VARCHAR(64),
  tier VARCHAR(64),
  description TEXT,
  description_raw TEXT,
  compendium_order INT DEFAULT 0,
  image VARCHAR(256),
  page VARCHAR(256)
) CHARACTER SET utf8mb4;

CREATE TABLE IF NOT EXISTS wiki_modifier (
  id INT AUTO_INCREMENT PRIMARY KEY,
  modifier_id VARCHAR(64),
  name VARCHAR(128),
  description TEXT,
  image VARCHAR(256),
  kind VARCHAR(32)
) CHARACTER SET utf8mb4;

DELETE FROM wiki_card;

DELETE FROM wiki_relic;

DELETE FROM wiki_potion;

